@function ms-grid($units, $ratio)
      $column-sum: 100%
      $grid-sum: 0%
      $column-ratio: $ratio
      $return: 0
      $column-short: false
      @if $ratio > 1
        $column-ratio: 1 / $ratio
      @for $i from 1 through $units
        $column-sum: ms($i, 100%, $column-ratio)
        $grid-sum: $column-sum + $grid-sum
        $return: $column-sum
        @if $grid-sum > 100%
          $return: 0%
          @if $column-short == false
            $column-short: $i
        @if $i == $columns
          @if $grid-sum < 100%
            $return: 100% - $grid-sum + $column-sum
        @if $column-short == $i
          $return: 100% - $grid-sum + $column-sum
      @return $return

@function colorLuminance($color)
  @if type-of($color) != 'color'
    @return 0.55
  $color-rgb: ('red': red($color),'green': green($color),'blue': blue($color))
  @each $name, $value in $color-rgb
    $adjusted: 0
    $value: $value / 255
    @if $value < 0.03928
      $value: $value / 12.92
    @else
      $value: ($value + .055) / 1.055
      $value: powerNumber($value, 2)
    $color-rgb: map-merge($color-rgb, ($name: $value))
  @return (map-get($color-rgb, 'red') * .2126) + (map-get($color-rgb, 'green') * .7152) + (map-get($color-rgb, 'blue') * .0722)

@function circular-progress($maxPercent, $percent, $color-bar, $color-back)
  $increment: 360 / $maxPercent
  $half: round($maxPercent / 2)
  $background-image: ""

  @if $percent < $half
    $nextdeg: 90deg + $increment * $percent

    $background-image: "linear-gradient(90deg, #{$color-back} 50%, transparent 50%, transparent),\a     linear-gradient(#{$nextdeg}, #{$color-bar} 50%, #{$color-back} 50%, #{$color-back})"
  @else
    $nextdeg: -90deg + $increment * ($percent - $half)

    $background-image: "linear-gradient(#{$nextdeg}, #{$color-bar} 50%, transparent 50%, transparent),\a       linear-gradient(270deg, #{$color-bar} 50%, #{$color-back} 50%, #{$color-back})"

  @return unquote($background-image)

@mixin sassy-button-text-style($base-color, $second-color, $text-color, $text-style: "inset")
  $text-lightness: lightness($text-color)
  $text-color-shift: 0
  $diff : lightness($base-color) - lightness($second-color)

  @if $diff > 40
    $text-color-shift: 35  + ($diff/10)
  @else if $diff > 18
    $text-color-shift: 30  + ($diff/10)
  @else
    $text-color-shift: 25  + ($diff/10)

  color: $text-color

  @if $text-style == "inset"
    @if $text-lightness < 50
      @include text-shadow(lighten($second-color, ($text-color-shift/1.5)) 0 1px 0)
    @else
      @include text-shadow(darken($base-color, $text-color-shift) 0 -1px 0)
  @if $text-style == "raised"
    @if $text-lightness < 50
      @include text-shadow(lighten($second-color, ($text-color-shift/1.5)) 0 -1px 0)
    @else
      @include text-shadow(darken($base-color, $text-color-shift) 0 1px 0)

@for $toc_level from 1 through 10
    .toctree-l#{$toc_level}.current .toctree-l#{$toc_level + 1}
      @extend %hide_show_toctree_ul

    @if $toc_level > 1
      li.toctree-l#{$toc_level}
        a
          @extend %toctree_link_color
        &.current
          > a
            padding: ($gutter / 4) ($gutter * ($toc_level - 1 + 0.5))

          li.toctree-l#{$toc_level + 1}  > a
            @extend %display_current_toctree_element
            padding: ($gutter / 4) ($gutter * ($toc_level + 0.5))
            padding-right: $gutter
        a:hover button.toctree-expand
          @extend %toctree_hover_link_color
    @if $toc_level > 2 and $toc_level < 5
      li.toctree-l#{$toc_level}
        @extend %shrink_toctree_element

@mixin states ($selector: '&::before', $active: true)
  @if string.slice(string.unquote($selector), 1, 1) != '&'
    $selector: #{'>'} #{$selector}

  &:hover
    #{$selector}
      opacity: calc(#{map.get(settings.$states, 'hover')} * var(--v-theme-overlay-multiplier))

  &:focus-visible
    #{$selector}
      opacity: calc(#{map.get(settings.$states, 'focus')} * var(--v-theme-overlay-multiplier))

  @supports not selector(:focus-visible)
    &:focus
      #{$selector}
        opacity: calc(#{map.get(settings.$states, 'focus')} * var(--v-theme-overlay-multiplier))

  @if ($active)
    &--active,
    &[aria-haspopup="menu"][aria-expanded="true"]
      @include active-states($selector)

@function from($value)
	$type: meta.type-of($value)

	@if $type == 'string'
		@return $value

	@if $type == 'map'
		@return '{' + to-string($value, $type) + '}'

	@if $type == 'list' or $type == 'arglist'
		$is-bracketed: list.is-bracketed($value)
		$value: to-string($value, $type)

		@return if($is-bracketed, '[' + $value + ']', '(' + $value + ')')

	@if $type == 'function'
		$value: meta.inspect($value)
		$value: string.slice($value, string.index($value, '"') + 1)
		$value: string.slice($value, 0, string.index($value, '"') - 1) + '()'

	@return '#{$value}'

